    std::any visitVarDecl(SpadeParser::VarDeclContext *ctx) override {
        auto decl = new Variable(ctx->name(), ctx->expr(),
                                 ctx->CONST() == null, !currentMethods.empty() ? Variable::VarKind::LOCAL : Variable::VarKind::GLOBAL);
        if (!currentMethods.empty())
            currentScopes.back()->addChild(decl);
        else
            currentPackages.back()->addChild(decl);
        return decl;
    }

