    std::any visitExpr(SpadeParser::ExprContext *ctx) {
#define DIRECT(type) else if (is<SpadeParser::type##ExprContext *>(ctx)) return visit##type##Expr(cast<SpadeParser::type##ExprContext *>(ctx))
        if (is<SpadeParser::UnaryExprContext *>(ctx))
            return visitUnaryExpr(cast<SpadeParser::UnaryExprContext *>(ctx));
        DIRECT(Elvis);
        DIRECT(Cast);
        DIRECT(Power);
        DIRECT(Factor);
        DIRECT(Term);
        DIRECT(Shift);
        DIRECT(BitAnd);
        DIRECT(BitXor);
        DIRECT(BitOr);
        DIRECT(Relational);
        DIRECT(Conditional);
        DIRECT(Not);
        DIRECT(And);
        DIRECT(Or);
        DIRECT(Ternary);
        DIRECT(Lambda);
        DIRECT(Assign);
        return null;
#undef DIRECT
    }

    std::any visitUnaryExpr(SpadeParser::UnaryExprContext *ctx) override {
        switch (ctx->op->getType()) {
            case SpadeLexer::BANG:
                break;
            case SpadeLexer::TILDE:
                break;
            case SpadeLexer::DASH:
                break;
            case SpadeLexer::PLUS:
                break;
            default:
                return visitPostfix(ctx->postfix());
        }
        return visitChildren(ctx);
    }

