    std::any visitConstant(SpadeParser::ConstantContext *ctx) override {
        if (ctx->TRUE() != null || ctx->FALSE() != null)
            return Type::BOOL;
        else if (ctx->NULL_() != null)
            return Type::NULL_TYPE;
        else if (ctx->literal() != null)
            return visitLiteral(ctx->literal());
        return null;
    }

    DeclNode *getCurrentNode() {
        DeclNode *currentNode = null;
        if (!currentScopes.empty())
            currentNode = currentScopes.back();
        else if (!currentMethods.empty())
            currentNode = currentMethods.back();
        else if (!currentTypes.empty())
            currentNode = currentTypes.back();
        else if (!currentPackages.empty())
            currentNode = currentPackages.back();
        return currentNode;
    }

    std::any visitLiteral(SpadeParser::LiteralContext *ctx) override {
        if (ctx->INTEGER() != null)
            return Type::INT;
        else if (ctx->FLOAT() != null)
            return Type::FLOAT;
        else if (ctx->STRING() != null)
            return Type::STRING;
        else if (ctx->IDENTIFIER() != null) {
            auto name = ctx->IDENTIFIER()->getText();
            for (DeclNode *node = getCurrentNode(); node != null; node = node->getParent()) {
                auto members = node->getMembers(name);
                if (members.empty()) continue;
                auto member = members[0];
                // todo add type support
                if (is<Variable *>(member)) return cast<Variable *>(member)->getType();
            }
        }
        return null;
    }

